/**
 * Use this endpoint after authorization or refresh to exchange grants for access, refresh, and ID tokens.
 * @summary OAuth2 token endpoint
 */
export const exchangeOAuth2Token = (
    oAuth2TokenRequest: OAuth2TokenRequest,
 signal?: AbortSignal
) => {
      
      const formUrlEncoded = new URLSearchParams();
formUrlEncoded.append(`grant_type`, oAuth2TokenRequest.grant_type)
if(oAuth2TokenRequest.code !== undefined) {
 formUrlEncoded.append(`code`, oAuth2TokenRequest.code)
 }
if(oAuth2TokenRequest.redirect_uri !== undefined) {
 formUrlEncoded.append(`redirect_uri`, oAuth2TokenRequest.redirect_uri)
 }
if(oAuth2TokenRequest.code_verifier !== undefined) {
 formUrlEncoded.append(`code_verifier`, oAuth2TokenRequest.code_verifier)
 }
if(oAuth2TokenRequest.refresh_token !== undefined) {
 formUrlEncoded.append(`refresh_token`, oAuth2TokenRequest.refresh_token)
 }
if(oAuth2TokenRequest.scope !== undefined) {
 formUrlEncoded.append(`scope`, oAuth2TokenRequest.scope)
 }

      return customFetch<OAuth2TokenResponse>(
      {url: `/oauth2/token`, method: 'POST',
      headers: {'Content-Type': 'application/x-www-form-urlencoded', },
       data: formUrlEncoded, signal
    },
      );
    }
  


